import java.util.List;

public int dfs(int currCity, int remainingHighways, int costSoFar, List<List<Integer>> highways, boolean[] visited) {
    if (remainingHighways == 0) {
        return costSoFar;
    }

    visited[currCity] = true;
    int maxCost = -1;

    for (List<Integer> highway : highways) {
        int nextCity = -1;
        if (highway.get(0) == currCity && !visited[highway.get(1)]) {
            nextCity = highway.get(1);
        } else if (highway.get(1) == currCity && !visited[highway.get(0)]) {
            nextCity = highway.get(0);
        }

        if (nextCity != -1) {
            int cost = dfs(nextCity, remainingHighways - 1, costSoFar + highway.get(2), highways, visited);
            maxCost = Math.max(maxCost, cost);
        }
    }

    visited[currCity] = false;
    return maxCost;
}

public int maxCost(int n, List<List<Integer>> highways, int k) {
    boolean[] visited = new boolean[n];
    int maxCost = -1;

    for (int i = 0; i < n; i++) {
        int cost = dfs(i, k, 0, highways, visited);
        maxCost = Math.max(maxCost, cost);
    }

    return maxCost;
}
```

